const CommonCheck=window.CommonCheck={isChecked:function(e){return $(e).is(":checked")},getCheckedValues:function(e){return $(e).filter(":checked").map(function(){return this.value}).get()},setChecked:function(e,c=!0){$(e).prop("checked",c).trigger("change")},toggleAll:function(e,c){const n=$(e).is(":checked");$(c).prop("checked",n).trigger("change")},bindAll:function(e,c){const n=()=>{const n=$(c),o=n.length,t=n.filter(":checked").length;$(e).prop("checked",o>0&&o===t)};$(document).off("change.commonCheckMaster",e).on("change.commonCheckMaster",e,()=>{this.toggleAll(e,c)}),$(document).off("change.commonCheckItem",c).on("change.commonCheckItem",c,n),n()}};